-- Minimal AUDIT_EVENTS schema, byte-identical to what Hibernate generates for
-- PersistentAuditEvent (dumped from a real app-created H2 DB). Lets a fresh demo
-- DB be seeded before first boot; ddl-auto=update then creates every other table
-- and leaves this one untouched (matched by name).
CREATE TABLE IF NOT EXISTS "PUBLIC"."AUDIT_EVENTS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1) NOT NULL,
    "DATA" CHARACTER LARGE OBJECT,
    "PRINCIPAL" CHARACTER VARYING(255),
    "TIMESTAMP" TIMESTAMP(6) WITH TIME ZONE,
    "TYPE" CHARACTER VARYING(255),
    CONSTRAINT "CONSTRAINT_C" PRIMARY KEY("ID")
);
CREATE INDEX IF NOT EXISTS "IDX_AUDIT_TIMESTAMP" ON "PUBLIC"."AUDIT_EVENTS"("TIMESTAMP" NULLS FIRST);
CREATE INDEX IF NOT EXISTS "IDX_AUDIT_PRINCIPAL" ON "PUBLIC"."AUDIT_EVENTS"("PRINCIPAL" NULLS FIRST);
CREATE INDEX IF NOT EXISTS "IDX_AUDIT_TYPE" ON "PUBLIC"."AUDIT_EVENTS"("TYPE" NULLS FIRST);
CREATE INDEX IF NOT EXISTS "IDX_AUDIT_PRINCIPAL_TYPE" ON "PUBLIC"."AUDIT_EVENTS"("PRINCIPAL" NULLS FIRST, "TYPE" NULLS FIRST);
CREATE INDEX IF NOT EXISTS "IDX_AUDIT_TYPE_TIMESTAMP" ON "PUBLIC"."AUDIT_EVENTS"("TYPE" NULLS FIRST, "TIMESTAMP" NULLS FIRST);
